// Edit src/scripts/bridge-lib/*.jsx (command handlers) or src/scripts/bridge-entry.jsx
// (UI/polling), then `npm run build` regenerates this file.

// ---- bridge-lib/json-polyfill.jsx ----
// JSON polyfill for ExtendScript (when JSON is undefined)
if (typeof JSON === "undefined") {
    JSON = {};
}
if (typeof JSON.parse !== "function") {
    JSON.parse = function (text) {
        // Safe-ish fallback for trusted input (our own command file)
        return eval("(" + text + ")");
    };
}
if (typeof JSON.stringify !== "function") {
    (function () {
        function esc(str) {
            return (str + "")
                .replace(/\\/g, "\\\\")
                .replace(/"/g, '\\"')
                .replace(/\n/g, "\\n")
                .replace(/\r/g, "\\r")
                .replace(/\t/g, "\\t")
                // Any other control char (U+0000-U+001F) is invalid unescaped in JSON;
                // an unescaped one here silently produces bad JSON that Node's parser
                // rejects, which the poll loop misreads as "not ready yet" and times out.
                .replace(new RegExp("[\x00-\x1f]", "g"), function (c) {
                    var code = c.charCodeAt(0).toString(16);
                    while (code.length < 4) code = "0" + code;
                    return "\\u" + code;
                });
        }
        function toJSON(val) {
            if (val === null) return "null";
            var t = typeof val;
            // NaN/Infinity have no JSON representation; emitting their literal names
            // produces invalid JSON that fails to parse on the Node side (same
            // false-timeout failure mode as the control-char case above).
            if (t === "number") return isFinite(val) ? String(val) : "null";
            if (t === "boolean") return String(val);
            if (t === "string") return '"' + esc(val) + '"';
            if (val instanceof Array) {
                var a = [];
                for (var i = 0; i < val.length; i++) a.push(toJSON(val[i]));
                return "[" + a.join(",") + "]";
            }
            if (t === "object") {
                var props = [];
                for (var k in val) {
                    if (val.hasOwnProperty(k) && typeof val[k] !== "function" && typeof val[k] !== "undefined") {
                        props.push('"' + esc(k) + '":' + toJSON(val[k]));
                    }
                }
                return "{" + props.join(",") + "}";
            }
            return "null";
        }
        JSON.stringify = function (value, _replacer, _space) {
            return toJSON(value);
        };
    })();
}

// ---- bridge-lib/utils.jsx ----
// Shared lookup/serialization helpers used across the other bridge-lib modules.

// Resolve a composition from args by name (preferred, robust across index shifts),
// then 1-based project index, then the active comp. Returns null if none match.
function resolveComp(args) {
    args = args || {};
    if (args.compName) {
        for (var i = 1; i <= app.project.numItems; i++) {
            var it = app.project.item(i);
            if (it instanceof CompItem && it.name === args.compName) return it;
        }
    }
    if (args.compIndex) {
        var byIdx = app.project.item(args.compIndex);
        if (byIdx instanceof CompItem) return byIdx;
    }
    if (app.project.activeItem instanceof CompItem) return app.project.activeItem;
    return null;
}

// Ambient "where are we" snapshot attached to every result, so the agent never has to
// guess whether app.project.activeItem was actually the comp it meant (it's null whenever
// a non-Composition panel, e.g. Effect Controls, has focus).
function getAmbientContext() {
    try {
        var ctx = { activeComp: null, time: null, selectedLayers: [] };
        if (app.project.activeItem instanceof CompItem) {
            var comp = app.project.activeItem;
            ctx.activeComp = comp.name;
            ctx.time = comp.time;
            var sel = comp.selectedLayers;
            for (var i = 0; i < sel.length; i++) ctx.selectedLayers.push(sel[i].name);
        }
        return ctx;
    } catch (e) {
        return { activeComp: null, time: null, selectedLayers: [] };
    }
}

// Walk a property path (e.g. ["Contents","Group 1","Rectangle Path 1","Size"] or
// ["Essential Properties","Target Size"]) starting from a layer, matching each segment
// by display name first, then matchName (agents read both off get-layer-tree output).
// On a dead end, the error names where it failed and what children WERE available, so
// a wrong guess is a one-retry fix instead of a stare-at-raw-JSX session.
function resolvePropertyPath(layer, pathArr) {
    var current = layer;
    for (var i = 0; i < pathArr.length; i++) {
        var seg = pathArr[i];
        var next = null;
        try { next = current.property(seg); } catch (e) { next = null; }
        if (!next) {
            for (var j = 1; j <= current.numProperties; j++) {
                var child = current.property(j);
                var childMatchName = null;
                try { childMatchName = child.matchName; } catch (e2) {}
                if (childMatchName === seg) { next = child; break; }
            }
        }
        if (!next) {
            var avail = [];
            for (var k = 1; k <= current.numProperties; k++) {
                try { avail.push(current.property(k).name); } catch (e3) {}
            }
            return { error: "'" + seg + "' not found under '" + (current.name || "layer") + "'. Children: [" + avail.join(", ") + "]" };
        }
        current = next;
    }
    return { property: current };
}

// Shared by getExpression/setExpressions/evaluateProperty: resolve comp -> layer ->
// property from a propertyPath, in one place instead of the transform/effects/text
// fallback maze duplicated in setLayerKeyframe/setLayerExpression. New tools require
// propertyPath (as returned by get-layer-tree) rather than re-supporting the old bare-
// propertyName shorthand.
function resolveLayerAndProperty(args) {
    var comp = resolveComp(args);
    if (!comp) return { error: "Composition not found (pass compName or compIndex, or open a comp)." };
    var layer = (args.layerIndex != null) ? comp.layers[args.layerIndex] : null;
    if (!layer && args.layerName) layer = comp.layers.byName(args.layerName);
    if (!layer) return { error: "Layer not found (pass layerIndex or layerName) in composition '" + comp.name + "'." };
    if (!args.propertyPath || !args.propertyPath.length) return { error: "propertyPath is required (array of property names/matchNames, as seen in get-layer-tree output)." };
    var resolved = resolvePropertyPath(layer, args.propertyPath);
    if (resolved.error) return { error: resolved.error };
    return { comp: comp, layer: layer, property: resolved.property, propertyLabel: args.propertyPath.join(" > ") };
}

// Human-readable name for a PropertyValueType (so the agent knows what shape a
// value is: color = 4-array, TwoD = 2-array, OneD = scalar, etc.).
function valueTypeName(t) {
    if (t === PropertyValueType.COLOR) return "COLOR";
    if (t === PropertyValueType.ThreeD || t === PropertyValueType.ThreeD_SPATIAL) return "ThreeD";
    if (t === PropertyValueType.TwoD || t === PropertyValueType.TwoD_SPATIAL) return "TwoD";
    if (t === PropertyValueType.OneD) return "OneD";
    if (t === PropertyValueType.LAYER_INDEX) return "LAYER_INDEX";
    if (t === PropertyValueType.MASK_INDEX) return "MASK_INDEX";
    if (t === PropertyValueType.TEXT_DOCUMENT) return "TEXT_DOCUMENT";
    if (t === PropertyValueType.SHAPE) return "SHAPE";
    if (t === PropertyValueType.CUSTOM_VALUE) return "CUSTOM_VALUE";
    if (t === PropertyValueType.MARKER) return "MARKER";
    if (t === PropertyValueType.NO_VALUE) return "NO_VALUE";
    return "" + t;
}

// List an effect's top-level properties so the agent can both SEE and set them:
// name + matchName, the current value, and its value type.
function listEffectProperties(effect) {
    var out = [];
    for (var i = 1; i <= effect.numProperties; i++) {
        var p = effect.property(i);
        var info = { index: i, name: p.name };
        try { info.matchName = p.matchName; } catch (e) {}
        try {
            if (p.propertyType === PropertyType.PROPERTY) {
                info.valueType = valueTypeName(p.propertyValueType);
                info.canSetExpression = p.canSetExpression;
                try { info.value = p.value; } catch (eV) {}
            } else {
                info.group = true;
            }
        } catch (e) {}
        out.push(info);
    }
    return out;
}

// Recursively collect any property that carries a non-empty expression.
function collectExpressions(propGroup, path, out) {
    for (var i = 1; i <= propGroup.numProperties; i++) {
        var p = propGroup.property(i);
        var name = (path ? path + " > " : "") + p.name;
        if (p.propertyType === PropertyType.PROPERTY) {
            if (p.canSetExpression && p.expressionEnabled && p.expression && p.expression !== "") {
                out.push({ prop: name, expression: p.expression });
            }
        } else if (p.numProperties > 0) {
            collectExpressions(p, name, out);
        }
    }
}

// ExtendScript's Date has no toISOString (ES3 engine) — build it manually.
function toISOStringCompat(d) {
    function pad(n, len) { n = String(n); while (n.length < (len || 2)) n = "0" + n; return n; }
    return d.getUTCFullYear() + "-" + pad(d.getUTCMonth() + 1) + "-" + pad(d.getUTCDate()) +
        "T" + pad(d.getUTCHours()) + ":" + pad(d.getUTCMinutes()) + ":" + pad(d.getUTCSeconds()) +
        "." + pad(d.getUTCMilliseconds(), 3) + "Z";
}

// ---- bridge-lib/project-info.jsx ----
// Read-only project/comp/layer inspection commands, plus comp-level mutations
// (duplicateComp, setCompositionProperties) that don't touch layer content.

function getProjectInfo() {
    var project = app.project;
    var result = {
        projectName: project.file ? project.file.name : "Untitled Project",
        path: project.file ? project.file.fsName : "",
        numItems: project.numItems,
        bitsPerChannel: project.bitsPerChannel,
        timeMode: project.timeDisplayType === TimeDisplayType.FRAMES ? "Frames" : "Timecode",
        items: []
    };

    var countByType = {
        compositions: 0,
        footage: 0,
        folders: 0,
        solids: 0
    };

    for (var i = 1; i <= Math.min(project.numItems, 50); i++) {
        var item = project.item(i);
        var itemType = "";

        if (item instanceof CompItem) {
            itemType = "Composition";
            countByType.compositions++;
        } else if (item instanceof FolderItem) {
            itemType = "Folder";
            countByType.folders++;
        } else if (item instanceof FootageItem) {
            if (item.mainSource instanceof SolidSource) {
                itemType = "Solid";
                countByType.solids++;
            } else {
                itemType = "Footage";
                countByType.footage++;
            }
        }

        result.items.push({
            id: item.id,
            name: item.name,
            type: itemType
        });
    }

    result.itemCounts = countByType;

    if (app.project.activeItem instanceof CompItem) {
        var ac = app.project.activeItem;
        result.activeComp = {
            id: ac.id,
            name: ac.name,
            width: ac.width,
            height: ac.height,
            duration: ac.duration,
            frameRate: ac.frameRate,
            numLayers: ac.numLayers
        };
    }

    return JSON.stringify(result, null, 2);
}

function listCompositions() {
    var project = app.project;
    var result = {
        compositions: []
    };

    for (var i = 1; i <= project.numItems; i++) {
        var item = project.item(i);

        if (item instanceof CompItem) {
            result.compositions.push({
                id: item.id,
                name: item.name,
                duration: item.duration,
                frameRate: item.frameRate,
                width: item.width,
                height: item.height,
                numLayers: item.numLayers
            });
        }
    }

    return JSON.stringify(result, null, 2);
}

// Single-call comp summary (dimensions, frameRate, duration, bgColor, pixelAspect) —
// folds what would otherwise be a run-jsx call for bgColor alone into the same
// round trip as everything getLayerTree/getProjectInfo already expose per-layer.
function getCompositionInfo(args) {
    args = args || {};
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ status: "error", message: "Composition not found (pass compName or compIndex, or open a comp)" });
    return JSON.stringify({
        status: "success",
        composition: {
            name: comp.name,
            id: comp.id,
            width: comp.width,
            height: comp.height,
            pixelAspect: comp.pixelAspect,
            duration: comp.duration,
            frameRate: comp.frameRate,
            frameDuration: comp.frameDuration,
            time: comp.time,
            bgColor: comp.bgColor,
            numLayers: comp.numLayers,
            workAreaStart: comp.workAreaStart,
            workAreaDuration: comp.workAreaDuration
        }
    }, null, 2);
}

function getLayerInfo(args) {
    args = args || {};
    // Accept compName/compIndex (general) or the legacy compositionName; else active comp.
    if (args.compositionName && !args.compName) args.compName = args.compositionName;
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ error: "Comp not found (pass compName/compIndex or open a comp)" }, null, 2);

    var result = { comp: comp.name, layers: [] };

    for (var i = 1; i <= comp.numLayers; i++) {
        var layer = comp.layer(i);
        var exprs = [];
        try { collectExpressions(layer, "", exprs); } catch (e) {}
        result.layers.push({
            index: layer.index,
            name: layer.name,
            enabled: layer.enabled,
            parent: layer.parent ? layer.parent.name : null,
            threeDLayer: layer.threeDLayer,
            position: layer.property("Position").value,
            inPoint: layer.inPoint,
            outPoint: layer.outPoint,
            expressions: exprs
        });
    }

    return JSON.stringify(result, null, 2);
}

// Structural property-tree dump for one layer (or every layer in a comp, if none named).
// Replaces the "8 run-jsx calls just to see the shape hierarchy" pattern. Per-property
// try/catch: a bad read (e.g. a shape Rect prop mid-eval throwing "divide by zero")
// becomes a "valueError" string on that one node instead of failing the whole call.
function getLayerTree(args) {
    args = args || {};
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ status: "error", message: "Composition not found (pass compName or compIndex, or open a comp)" });

    var maxDepth = args.depth || 4;
    var maxNodes = args.maxNodes || 500;
    var counter = { count: 0, truncated: false };

    function safeValue(prop) {
        try {
            var v = prop.valueAtTime(comp.time, false);
            try { JSON.stringify(v); return { value: v }; }
            catch (serErr) { return { value: String(v) }; }
        } catch (e) {
            return { valueError: e.toString() };
        }
    }

    function walkProp(prop, depth) {
        if (counter.truncated) return null;
        counter.count++;
        if (counter.count > maxNodes) { counter.truncated = true; return null; }

        var node = { name: prop.name };
        try { node.matchName = prop.matchName; } catch (e0) {}

        if (prop.propertyType === PropertyType.PROPERTY) {
            var vr = safeValue(prop);
            if (vr.valueError) node.valueError = vr.valueError; else node.value = vr.value;
            try {
                if (prop.canSetExpression && prop.expressionEnabled && prop.expression) {
                    var expr = prop.expression;
                    if (expr.length > 200) { node.expression = expr.substring(0, 200); node.expressionTruncated = true; }
                    else node.expression = expr;
                }
            } catch (e1) {}
            try { if (prop.numKeys > 0) node.numKeys = prop.numKeys; } catch (e2) {}
        } else {
            if (depth < maxDepth) {
                node.children = [];
                for (var i = 1; i <= prop.numProperties; i++) {
                    if (counter.truncated) break;
                    var child = walkProp(prop.property(i), depth + 1);
                    if (child) node.children.push(child);
                }
            } else {
                node.truncatedDepth = true;
            }
        }
        return node;
    }

    function nodeForLayer(layer) {
        var node = { name: layer.name, matchName: layer.matchName, children: [] };
        for (var i = 1; i <= layer.numProperties; i++) {
            if (counter.truncated) break;
            var child = walkProp(layer.property(i), 1);
            if (child) node.children.push(child);
        }
        return node;
    }

    var result = { comp: comp.name };
    if (args.namesOnly) {
        result.layers = [];
        for (var ni = 1; ni <= comp.numLayers; ni++) {
            var nl = comp.layer(ni);
            result.layers.push({ index: nl.index, name: nl.name, matchName: nl.matchName });
        }
        return JSON.stringify(result, null, 2);
    }
    if (args.layerIndex || args.layerName) {
        var layer = null;
        if (args.layerIndex) {
            if (args.layerIndex > 0 && args.layerIndex <= comp.numLayers) layer = comp.layer(args.layerIndex);
        } else {
            for (var li = 1; li <= comp.numLayers; li++) {
                if (comp.layer(li).name === args.layerName) { layer = comp.layer(li); break; }
            }
        }
        if (!layer) return JSON.stringify({ status: "error", message: "Layer not found: " + (args.layerName || "index " + args.layerIndex) });
        result.layer = nodeForLayer(layer);
    } else {
        result.layers = [];
        for (var i2 = 1; i2 <= comp.numLayers; i2++) {
            if (counter.truncated) break;
            result.layers.push(nodeForLayer(comp.layer(i2)));
        }
    }
    if (counter.truncated) result.truncated = true;
    return JSON.stringify(result, null, 2);
}

// Duplicate a composition (source by name, index, or the active comp).
function duplicateComp(args) {
    args = args || {};
    var src = null;
    if (args.compName) {
        for (var i = 1; i <= app.project.numItems; i++) {
            var it = app.project.item(i);
            if (it instanceof CompItem && it.name === args.compName) { src = it; break; }
        }
    } else if (args.compIndex) {
        var byIdx = app.project.item(args.compIndex);
        if (byIdx instanceof CompItem) src = byIdx;
    } else if (app.project.activeItem instanceof CompItem) {
        src = app.project.activeItem;
    }
    if (!src) return JSON.stringify({ status: "error", message: "Source comp not found (pass compName or compIndex, or open a comp)" });

    app.beginUndoGroup("Duplicate composition");
    try {
        var dup = src.duplicate();
        if (args.newName) dup.name = args.newName;
        app.endUndoGroup();
        return JSON.stringify({
            status: "success",
            message: "Duplicated '" + src.name + "' -> '" + dup.name + "'",
            comp: { name: dup.name, id: dup.id, numLayers: dup.numLayers }
        }, null, 2);
    } catch (e) {
        app.endUndoGroup();
        return JSON.stringify({ status: "error", message: e.toString() });
    }
}

// --- setCompositionProperties: set duration, frameRate, etc. on active or named comp ---
function setCompositionProperties(args) {
    try {
        var compName = args.compName || "";
        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }
        var changed = [];
        if (args.duration !== undefined && args.duration !== null) { comp.duration = args.duration; changed.push("duration"); }
        if (args.frameRate !== undefined && args.frameRate !== null) { comp.frameRate = args.frameRate; changed.push("frameRate"); }
        if (args.width !== undefined && args.width !== null && args.height !== undefined && args.height !== null) {
            comp.width = args.width; comp.height = args.height; changed.push("dimensions");
        }
        return JSON.stringify({
            status: "success",
            composition: { name: comp.name, duration: comp.duration, frameRate: comp.frameRate, width: comp.width, height: comp.height },
            changedProperties: changed
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// ---- bridge-lib/layers.jsx ----
// Layer CRUD: create (comp/text/shape/solid/camera), duplicate, delete, batch property
// set, masks. Each function resolves its own comp (by compName else active comp) since
// these predate the shared resolveComp() helper's compIndex support in some call sites.

// --- createComposition (from createComposition.jsx) ---
function createComposition(args) {
    try {
        var name = args.name || "New Composition";
        var width = parseInt(args.width) || 1920;
        var height = parseInt(args.height) || 1080;
        var pixelAspect = parseFloat(args.pixelAspect) || 1.0;
        var duration = parseFloat(args.duration) || 10.0;
        var frameRate = parseFloat(args.frameRate) || 30.0;
        var bgColor = args.backgroundColor ? [args.backgroundColor.r/255, args.backgroundColor.g/255, args.backgroundColor.b/255] : [0, 0, 0];
        var newComp = app.project.items.addComp(name, width, height, pixelAspect, duration, frameRate);
        if (args.backgroundColor) {
            newComp.bgColor = bgColor;
        }
        return JSON.stringify({
            status: "success", message: "Composition created successfully",
            composition: { name: newComp.name, id: newComp.id, width: newComp.width, height: newComp.height, pixelAspect: newComp.pixelAspect, duration: newComp.duration, frameRate: newComp.frameRate, bgColor: newComp.bgColor }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- createTextLayer (from createTextLayer.jsx) ---
function createTextLayer(args) {
    try {
        var compName = args.compName || "";
        var text = args.text || "Text Layer";
        var position = args.position || [960, 540];
        var fontSize = args.fontSize || 72;
        var color = args.color || [1, 1, 1];
        var startTime = args.startTime || 0;
        var duration = args.duration || 5;
        var fontFamily = args.fontFamily || "Arial";
        var alignment = args.alignment || "center";
        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }
        var textLayer = comp.layers.addText(text);
        var textProp = textLayer.property("ADBE Text Properties").property("ADBE Text Document");
        var textDocument = textProp.value;
        textDocument.fontSize = fontSize;
        textDocument.fillColor = color;
        textDocument.font = fontFamily;
        if (alignment === "left") { textDocument.justification = ParagraphJustification.LEFT_JUSTIFY; }
        else if (alignment === "center") { textDocument.justification = ParagraphJustification.CENTER_JUSTIFY; }
        else if (alignment === "right") { textDocument.justification = ParagraphJustification.RIGHT_JUSTIFY; }
        textProp.setValue(textDocument);
        textLayer.property("Position").setValue(position);
        textLayer.startTime = startTime;
        if (duration > 0) { textLayer.outPoint = startTime + duration; }
        return JSON.stringify({
            status: "success", message: "Text layer created successfully",
            layer: { name: textLayer.name, index: textLayer.index, type: "text", inPoint: textLayer.inPoint, outPoint: textLayer.outPoint, position: textLayer.property("Position").value }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- createShapeLayer (from createShapeLayer.jsx) ---
function createShapeLayer(args) {
    try {
        var compName = args.compName || "";
        var shapeType = args.shapeType || "rectangle";
        var position = args.position || [960, 540];
        var size = args.size || [200, 200];
        var fillColor = args.fillColor || [1, 0, 0];
        var strokeColor = args.strokeColor || [0, 0, 0];
        var strokeWidth = args.strokeWidth || 0;
        var startTime = args.startTime || 0;
        var duration = args.duration || 5;
        var name = args.name || "Shape Layer";
        var points = args.points || 5;
        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }
        var shapeLayer = comp.layers.addShape();
        shapeLayer.name = name;
        var contents = shapeLayer.property("Contents");
        var shapeGroup = contents.addProperty("ADBE Vector Group");
        var groupContents = shapeGroup.property("Contents");
        var shapePathProperty;
        if (shapeType === "rectangle") {
            shapePathProperty = groupContents.addProperty("ADBE Vector Shape - Rect");
            shapePathProperty.property("Size").setValue(size);
        } else if (shapeType === "ellipse") {
            shapePathProperty = groupContents.addProperty("ADBE Vector Shape - Ellipse");
            shapePathProperty.property("Size").setValue(size);
        } else if (shapeType === "polygon" || shapeType === "star") {
            shapePathProperty = groupContents.addProperty("ADBE Vector Shape - Star");
            shapePathProperty.property("Type").setValue(shapeType === "polygon" ? 1 : 2);
            shapePathProperty.property("Points").setValue(points);
            shapePathProperty.property("Outer Radius").setValue(size[0] / 2);
            if (shapeType === "star") { shapePathProperty.property("Inner Radius").setValue(size[0] / 3); }
        }
        var fill = groupContents.addProperty("ADBE Vector Graphic - Fill");
        fill.property("Color").setValue(fillColor);
        fill.property("Opacity").setValue(100);
        if (strokeWidth > 0) {
            var stroke = groupContents.addProperty("ADBE Vector Graphic - Stroke");
            stroke.property("Color").setValue(strokeColor);
            stroke.property("Stroke Width").setValue(strokeWidth);
            stroke.property("Opacity").setValue(100);
        }
        shapeLayer.property("Position").setValue(position);
        shapeLayer.startTime = startTime;
        if (duration > 0) { shapeLayer.outPoint = startTime + duration; }
        return JSON.stringify({
            status: "success", message: "Shape layer created successfully",
            layer: { name: shapeLayer.name, index: shapeLayer.index, type: "shape", shapeType: shapeType, inPoint: shapeLayer.inPoint, outPoint: shapeLayer.outPoint, position: shapeLayer.property("Position").value }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- createCamera ---
function createCamera(args) {
    try {
        var compName = args.compName || "";
        var name = args.name || "Camera";
        var zoom = args.zoom || 1777.78; // Default ~50mm equivalent
        var position = args.position; // Optional [x, y, z]
        var pointOfInterest = args.pointOfInterest; // Optional [x, y, z]
        var oneNode = args.oneNode || false; // If true, create a one-node camera (no point of interest)

        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }

        var centerPoint = [comp.width / 2, comp.height / 2];
        var cameraLayer = comp.layers.addCamera(name, centerPoint);
        cameraLayer.property("Camera Options").property("Zoom").setValue(zoom);

        if (oneNode) {
            cameraLayer.autoOrient = AutoOrientType.NO_AUTO_ORIENT;
        }

        if (position !== undefined && position !== null) {
            cameraLayer.property("Position").setValue(position);
        }

        if (pointOfInterest !== undefined && pointOfInterest !== null && !oneNode) {
            cameraLayer.property("Point of Interest").setValue(pointOfInterest);
        }

        var result = {
            name: cameraLayer.name,
            index: cameraLayer.index,
            zoom: cameraLayer.property("Camera Options").property("Zoom").value,
            position: cameraLayer.property("Position").value,
            oneNode: oneNode
        };
        if (!oneNode) {
            result.pointOfInterest = cameraLayer.property("Point of Interest").value;
        }

        return JSON.stringify({
            status: "success",
            message: "Camera created successfully",
            layer: result
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- duplicateLayer ---
function duplicateLayer(args) {
    try {
        var compName = args.compName || "";
        var layerIndex = args.layerIndex;
        var layerName = args.layerName || "";
        var newName = args.newName; // optional rename

        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }

        var layer = null;
        if (layerIndex !== undefined && layerIndex !== null) {
            if (layerIndex > 0 && layerIndex <= comp.numLayers) { layer = comp.layer(layerIndex); }
            else { throw new Error("Layer index out of bounds: " + layerIndex); }
        } else if (layerName) {
            for (var j = 1; j <= comp.numLayers; j++) {
                if (comp.layer(j).name === layerName) { layer = comp.layer(j); break; }
            }
        }
        if (!layer) { throw new Error("Layer not found: " + (layerName || "index " + layerIndex)); }

        var newLayer = layer.duplicate();
        if (newName) { newLayer.name = newName; }

        return JSON.stringify({
            status: "success",
            message: "Layer duplicated successfully",
            original: { name: layer.name, index: layer.index },
            duplicate: { name: newLayer.name, index: newLayer.index }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

