// --- setLayerMask: create or modify a mask on a layer ---
function setLayerMask(args) {
    try {
        var compName = args.compName || "";
        var layerIndex = args.layerIndex;
        var layerName = args.layerName || "";
        var maskIndex = args.maskIndex; // optional — if provided, modify existing mask
        var maskPath = args.maskPath; // array of [x, y] points defining the mask shape
        var maskRect = args.maskRect; // shorthand: {top, left, width, height} for rectangular masks
        var maskMode = args.maskMode || "add"; // "add", "subtract", "intersect", "none"
        var maskFeather = args.maskFeather; // optional [x, y] feather
        var maskOpacity = args.maskOpacity; // optional 0-100
        var maskExpansion = args.maskExpansion; // optional pixels
        var maskName = args.maskName; // optional rename

        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }

        var layer = null;
        if (layerIndex !== undefined && layerIndex !== null) {
            if (layerIndex > 0 && layerIndex <= comp.numLayers) { layer = comp.layer(layerIndex); }
            else { throw new Error("Layer index out of bounds: " + layerIndex); }
        } else if (layerName) {
            for (var j = 1; j <= comp.numLayers; j++) {
                if (comp.layer(j).name === layerName) { layer = comp.layer(j); break; }
            }
        }
        if (!layer) { throw new Error("Layer not found: " + (layerName || "index " + layerIndex)); }

        // Build the mask shape
        var shapePoints = [];
        if (maskRect) {
            // Rectangle shorthand
            var t = maskRect.top || 0;
            var l = maskRect.left || 0;
            var w = maskRect.width || comp.width;
            var h = maskRect.height || comp.height;
            shapePoints = [[l, t], [l + w, t], [l + w, t + h], [l, t + h]];
        } else if (maskPath && maskPath.length >= 3) {
            shapePoints = maskPath;
        } else {
            throw new Error("Must provide either maskRect or maskPath with at least 3 points");
        }

        // Create the shape object
        var myShape = new Shape();
        var vertices = [];
        for (var p = 0; p < shapePoints.length; p++) {
            vertices.push(shapePoints[p]);
        }
        myShape.vertices = vertices;
        myShape.closed = true;

        var changed = [];
        var mask;

        if (maskIndex !== undefined && maskIndex !== null) {
            // Modify existing mask
            if (maskIndex > 0 && maskIndex <= layer.property("Masks").numProperties) {
                mask = layer.property("Masks").property(maskIndex);
            } else {
                throw new Error("Mask index out of bounds: " + maskIndex);
            }
            mask.property("Mask Path").setValue(myShape);
            changed.push("maskPath");
        } else {
            // Create new mask
            mask = layer.property("Masks").addProperty("Mask");
            mask.property("Mask Path").setValue(myShape);
            changed.push("newMask");
        }

        // Set mask mode
        var modes = {
            "none": MaskMode.NONE,
            "add": MaskMode.ADD,
            "subtract": MaskMode.SUBTRACT,
            "intersect": MaskMode.INTERSECT,
            "lighten": MaskMode.LIGHTEN,
            "darken": MaskMode.DARKEN,
            "difference": MaskMode.DIFFERENCE
        };
        if (modes[maskMode] !== undefined) {
            mask.maskMode = modes[maskMode];
            changed.push("maskMode");
        }

        if (maskFeather !== undefined && maskFeather !== null) {
            mask.property("Mask Feather").setValue(maskFeather);
            changed.push("maskFeather");
        }
        if (maskOpacity !== undefined && maskOpacity !== null) {
            mask.property("Mask Opacity").setValue(maskOpacity);
            changed.push("maskOpacity");
        }
        if (maskExpansion !== undefined && maskExpansion !== null) {
            mask.property("Mask Expansion").setValue(maskExpansion);
            changed.push("maskExpansion");
        }
        if (maskName) {
            mask.name = maskName;
            changed.push("maskName");
        }

        return JSON.stringify({
            status: "success",
            message: "Mask set successfully",
            layer: { name: layer.name, index: layer.index },
            mask: {
                name: mask.name,
                index: mask.propertyIndex,
                mode: maskMode,
                changedProperties: changed
            }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- createSolidLayer (from createSolidLayer.jsx) ---
function createSolidLayer(args) {
    try {
        var compName = args.compName || "";
        var color = args.color || [1, 1, 1];
        var name = args.name || "Solid Layer";
        var position = args.position || [960, 540];
        var size = args.size;
        var startTime = args.startTime || 0;
        var duration = args.duration || 5;
        var isAdjustment = args.isAdjustment || false;
        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }
        if (!size) { size = [comp.width, comp.height]; }
        var solidLayer;
        if (isAdjustment) {
            solidLayer = comp.layers.addSolid([0, 0, 0], name, size[0], size[1], 1);
            solidLayer.adjustmentLayer = true;
        } else {
            solidLayer = comp.layers.addSolid(color, name, size[0], size[1], 1);
        }
        solidLayer.property("Position").setValue(position);
        solidLayer.startTime = startTime;
        if (duration > 0) { solidLayer.outPoint = startTime + duration; }
        return JSON.stringify({
            status: "success", message: isAdjustment ? "Adjustment layer created successfully" : "Solid layer created successfully",
            layer: { name: solidLayer.name, index: solidLayer.index, type: isAdjustment ? "adjustment" : "solid", inPoint: solidLayer.inPoint, outPoint: solidLayer.outPoint, position: solidLayer.property("Position").value, isAdjustment: solidLayer.adjustmentLayer }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- setLayerProperties (modified to handle text properties) ---
function setLayerProperties(args) {
    try {
        var compName = args.compName || "";
        var layerName = args.layerName || "";
        var layerIndex = args.layerIndex;

        // General Properties
        var position = args.position;
        var scale = args.scale;
        var rotation = args.rotation;
        var opacity = args.opacity;
        var startTime = args.startTime;
        var duration = args.duration;

        // Text Specific Properties
        var textContent = args.text; // New: text content
        var fontFamily = args.fontFamily; // New: font family
        var fontSize = args.fontSize; // New: font size
        var fillColor = args.fillColor; // New: font color

        // Find the composition (same logic as before)
        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }

        // Find the layer (same logic as before)
        var layer = null;
        if (layerIndex !== undefined && layerIndex !== null) {
            if (layerIndex > 0 && layerIndex <= comp.numLayers) { layer = comp.layer(layerIndex); }
            else { throw new Error("Layer index out of bounds: " + layerIndex); }
        } else if (layerName) {
            for (var j = 1; j <= comp.numLayers; j++) {
                if (comp.layer(j).name === layerName) { layer = comp.layer(j); break; }
            }
        }
        if (!layer) { throw new Error("Layer not found: " + (layerName || "index " + layerIndex)); }

        var changedProperties = [];
        var textDocumentChanged = false;
        var textProp = null;
        var textDocument = null;

        // --- Text Property Handling ---
        if (layer instanceof TextLayer && (textContent !== undefined || fontFamily !== undefined || fontSize !== undefined || fillColor !== undefined)) {
            var sourceTextProp = layer.property("Source Text");
            if (sourceTextProp && sourceTextProp.value) {
                var currentTextDocument = sourceTextProp.value; // Get the current value
                var updated = false;

                if (textContent !== undefined && textContent !== null && currentTextDocument.text !== textContent) {
                    currentTextDocument.text = textContent;
                    changedProperties.push("text");
                    updated = true;
                }
                if (fontFamily !== undefined && fontFamily !== null && currentTextDocument.font !== fontFamily) {
                    currentTextDocument.font = fontFamily;
                    changedProperties.push("fontFamily");
                    updated = true;
                }
                if (fontSize !== undefined && fontSize !== null && currentTextDocument.fontSize !== fontSize) {
                    currentTextDocument.fontSize = fontSize;
                    changedProperties.push("fontSize");
                    updated = true;
                }
                // Comparing colors needs care due to potential floating point inaccuracies if set via UI
                if (fillColor !== undefined && fillColor !== null &&
                    (currentTextDocument.fillColor[0] !== fillColor[0] ||
                     currentTextDocument.fillColor[1] !== fillColor[1] ||
                     currentTextDocument.fillColor[2] !== fillColor[2])) {
                    currentTextDocument.fillColor = fillColor;
                    changedProperties.push("fillColor");
                    updated = true;
                }

                // Only set the value if something actually changed
                if (updated) {
                    try {
                        sourceTextProp.setValue(currentTextDocument);
                        logToPanel("Applied changes to Text Document for layer: " + layer.name);
                    } catch (e) {
                        logToPanel("ERROR applying Text Document changes: " + e.toString());
                    }
                }
                 // Store the potentially updated document for the return value
                 textDocument = currentTextDocument;

            } else {
                logToPanel("Warning: Could not access Source Text property for layer: " + layer.name);
            }
        }

        // --- Enabled/Visible ---
        var enabled = args.enabled;
        if (enabled !== undefined && enabled !== null) { layer.enabled = !!enabled; changedProperties.push("enabled"); }

        // --- Blend Mode ---
        var blendMode = args.blendMode;
        if (blendMode !== undefined && blendMode !== null) {
            var modes = {
                "normal": BlendingMode.NORMAL,
                "add": BlendingMode.ADD,
                "multiply": BlendingMode.MULTIPLY,
                "screen": BlendingMode.SCREEN,
                "overlay": BlendingMode.OVERLAY,
                "softLight": BlendingMode.SOFT_LIGHT,
                "hardLight": BlendingMode.HARD_LIGHT,
                "colorDodge": BlendingMode.COLOR_DODGE,
                "colorBurn": BlendingMode.COLOR_BURN,
                "darken": BlendingMode.DARKEN,
                "lighten": BlendingMode.LIGHTEN,
                "difference": BlendingMode.DIFFERENCE,
                "exclusion": BlendingMode.EXCLUSION,
                "hue": BlendingMode.HUE,
                "saturation": BlendingMode.SATURATION,
                "color": BlendingMode.COLOR,
                "luminosity": BlendingMode.LUMINOSITY
            };
            if (modes[blendMode] !== undefined) {
                layer.blendingMode = modes[blendMode];
                changedProperties.push("blendMode");
            }
        }

        // --- Track Matte ---
        var trackMatteType = args.trackMatteType;
        if (trackMatteType !== undefined && trackMatteType !== null) {
            // Values: "none", "alpha", "alphaInverted", "luma", "lumaInverted"
            var matteTypes = {
                "none": TrackMatteType.NO_TRACK_MATTE,
                "alpha": TrackMatteType.ALPHA,
                "alphaInverted": TrackMatteType.ALPHA_INVERTED,
                "luma": TrackMatteType.LUMA,
                "lumaInverted": TrackMatteType.LUMA_INVERTED
            };
            if (matteTypes[trackMatteType] !== undefined) {
                layer.trackMatteType = matteTypes[trackMatteType];
                changedProperties.push("trackMatteType");
            }
        }

        // --- General Property Handling ---
        var threeDLayer = args.threeDLayer;
        if (threeDLayer !== undefined && threeDLayer !== null) { layer.threeDLayer = !!threeDLayer; changedProperties.push("threeDLayer"); }
        if (position !== undefined && position !== null) {
            var posProp = layer.property("Position");
            if (posProp.numKeys > 0) { while (posProp.numKeys > 0) { posProp.removeKey(1); } }
            posProp.setValue(position);
            changedProperties.push("position");
        }
        if (scale !== undefined && scale !== null) { layer.property("Scale").setValue(scale); changedProperties.push("scale"); }
        if (rotation !== undefined && rotation !== null) {
            if (layer.threeDLayer) {
                // For 3D layers, Z rotation is often what's intended by a single value
                layer.property("Z Rotation").setValue(rotation);
            } else {
                layer.property("Rotation").setValue(rotation);
            }
            changedProperties.push("rotation");
        }
        if (opacity !== undefined && opacity !== null) { layer.property("Opacity").setValue(opacity); changedProperties.push("opacity"); }
        if (startTime !== undefined && startTime !== null) { layer.startTime = startTime; changedProperties.push("startTime"); }
        if (duration !== undefined && duration !== null && duration > 0) {
            var actualStartTime = (startTime !== undefined && startTime !== null) ? startTime : layer.startTime;
            layer.outPoint = actualStartTime + duration;
            changedProperties.push("duration");
        }

        // Return success with updated layer details (including text if changed)
        var returnLayerInfo = {
            name: layer.name,
            index: layer.index,
            threeDLayer: layer.threeDLayer,
            position: layer.property("Position").value,
            scale: layer.property("Scale").value,
            rotation: layer.threeDLayer ? layer.property("Z Rotation").value : layer.property("Rotation").value, // Return appropriate rotation
            opacity: layer.property("Opacity").value,
            inPoint: layer.inPoint,
            outPoint: layer.outPoint,
            changedProperties: changedProperties
        };
        // Add text properties to the return object if it was a text layer
        if (layer instanceof TextLayer && textDocument) {
            returnLayerInfo.text = textDocument.text;
            returnLayerInfo.fontFamily = textDocument.font;
            returnLayerInfo.fontSize = textDocument.fontSize;
            returnLayerInfo.fillColor = textDocument.fillColor;
        }

        logToPanel("Final check before return:");
        logToPanel("  Changed Properties: " + changedProperties.join(", "));
        logToPanel("  Return Layer Info Font: " + (returnLayerInfo.fontFamily || "N/A"));
        logToPanel("  TextDocument Font: " + (textDocument ? textDocument.font : "N/A"));

        return JSON.stringify({
            status: "success", message: "Layer properties updated successfully",
            layer: returnLayerInfo
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// --- batchSetLayerProperties: apply properties to multiple layers in one call ---
function batchSetLayerProperties(args) {
    try {
        var compName = args.compName || "";
        var operations = args.operations; // Array of {layerIndex, threeDLayer, position, scale, rotation, opacity, ...}

        if (!operations || !operations.length) {
            throw new Error("No operations provided. Pass an array of {layerIndex, ...properties}");
        }

        var comp = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var item = app.project.item(i);
            if (item instanceof CompItem && item.name === compName) { comp = item; break; }
        }
        if (!comp) {
            if (app.project.activeItem instanceof CompItem) { comp = app.project.activeItem; }
            else { throw new Error("No composition found with name '" + compName + "' and no active composition"); }
        }

        var results = [];
        for (var o = 0; o < operations.length; o++) {
            var op = operations[o];
            var layer = null;
            if (op.layerIndex !== undefined && op.layerIndex !== null) {
                if (op.layerIndex > 0 && op.layerIndex <= comp.numLayers) { layer = comp.layer(op.layerIndex); }
                else { results.push({ layerIndex: op.layerIndex, status: "error", message: "Layer index out of bounds" }); continue; }
            } else if (op.layerName) {
                for (var j = 1; j <= comp.numLayers; j++) {
                    if (comp.layer(j).name === op.layerName) { layer = comp.layer(j); break; }
                }
            }
            if (!layer) { results.push({ layerIndex: op.layerIndex, layerName: op.layerName, status: "error", message: "Layer not found" }); continue; }

            var changed = [];
            if (op.threeDLayer !== undefined && op.threeDLayer !== null) { layer.threeDLayer = !!op.threeDLayer; changed.push("threeDLayer"); }
            if (op.position !== undefined && op.position !== null) {
                var posProp = layer.property("Position");
                if (posProp.numKeys > 0) {
                    while (posProp.numKeys > 0) { posProp.removeKey(1); }
                }
                posProp.setValue(op.position);
                changed.push("position");
            }
            if (op.scale !== undefined && op.scale !== null) { layer.property("Scale").setValue(op.scale); changed.push("scale"); }
            if (op.rotation !== undefined && op.rotation !== null) {
                if (layer.threeDLayer) { layer.property("Z Rotation").setValue(op.rotation); }
                else { layer.property("Rotation").setValue(op.rotation); }
                changed.push("rotation");
            }
            if (op.opacity !== undefined && op.opacity !== null) { layer.property("Opacity").setValue(op.opacity); changed.push("opacity"); }
            if (op.blendMode !== undefined && op.blendMode !== null) {
                var bModes = {"normal":BlendingMode.NORMAL,"add":BlendingMode.ADD,"multiply":BlendingMode.MULTIPLY,"screen":BlendingMode.SCREEN,"overlay":BlendingMode.OVERLAY,"softLight":BlendingMode.SOFT_LIGHT,"hardLight":BlendingMode.HARD_LIGHT,"darken":BlendingMode.DARKEN,"lighten":BlendingMode.LIGHTEN,"difference":BlendingMode.DIFFERENCE};
                if (bModes[op.blendMode] !== undefined) { layer.blendingMode = bModes[op.blendMode]; changed.push("blendMode"); }
            }
            if (op.startTime !== undefined && op.startTime !== null) { layer.startTime = op.startTime; changed.push("startTime"); }
            if (op.outPoint !== undefined && op.outPoint !== null) { layer.outPoint = op.outPoint; changed.push("outPoint"); }

            results.push({
                layerIndex: layer.index,
                name: layer.name,
                status: "success",
                threeDLayer: layer.threeDLayer,
                position: layer.property("Position").value,
                changedProperties: changed
            });
        }

        return JSON.stringify({ status: "success", results: results }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// ---- bridge-lib/keyframes-expressions.jsx ----
// Keyframe/expression get-set commands. Depends on resolveComp/resolvePropertyPath/
// resolveLayerAndProperty from utils.jsx.

function setLayerKeyframe(args) {
    try {
        var layerIndex = args.layerIndex, propertyName = args.propertyName,
            timeInSeconds = args.timeInSeconds, value = args.value;
        var comp = resolveComp(args);
        if (!comp) {
            return JSON.stringify({ success: false, message: "Composition not found (pass compName or compIndex, or open a comp)" });
        }
        var layer = comp.layers[layerIndex];
        if (!layer) {
            return JSON.stringify({ success: false, message: "Layer not found at index " + layerIndex + " in composition '" + comp.name + "'"});
        }

        var property;
        var propertyLabel;
        if (args.propertyPath && args.propertyPath.length) {
            var resolved = resolvePropertyPath(layer, args.propertyPath);
            if (resolved.error) return JSON.stringify({ success: false, message: resolved.error });
            property = resolved.property;
            propertyLabel = args.propertyPath.join(" > ");
        } else {
            var transformGroup = layer.property("Transform");
            if (!transformGroup) {
                 return JSON.stringify({ success: false, message: "Transform properties not found for layer '" + layer.name + "' (type: " + layer.matchName + ")." });
            }

            property = transformGroup.property(propertyName);
            if (!property) {
                 if (layer.property("Effects") && layer.property("Effects").property(propertyName)) {
                     property = layer.property("Effects").property(propertyName);
                 } else if (layer.property("Text") && layer.property("Text").property(propertyName)) {
                     property = layer.property("Text").property(propertyName);
                }

                if (!property) {
                     return JSON.stringify({ success: false, message: "Property '" + propertyName + "' not found on layer '" + layer.name + "'." });
                }
            }
            propertyLabel = propertyName;
        }

        // Ensure the property can be keyframed
        if (!property.canVaryOverTime) {
             return JSON.stringify({ success: false, message: "Property '" + propertyLabel + "' cannot be keyframed." });
        }

        // Make sure the property is enabled for keyframing
        if (property.numKeys === 0 && !property.isTimeVarying) {
             property.setValueAtTime(comp.time, property.value); // Set initial keyframe if none exist
        }

        property.setValueAtTime(timeInSeconds, value);

        return JSON.stringify({ success: true, message: "Keyframe set for '" + propertyLabel + "' on layer '" + layer.name + "' at " + timeInSeconds + "s." });
    } catch (e) {
        return JSON.stringify({ success: false, message: "Error setting keyframe: " + e.toString() + " (Line: " + e.line + ")" });
    }
}

function setLayerExpression(args) {
    try {
        var layerIndex = args.layerIndex, propertyName = args.propertyName,
            expressionString = args.expressionString;
        var comp = resolveComp(args);
         if (!comp) {
            return JSON.stringify({ success: false, message: "Composition not found (pass compName or compIndex, or open a comp)" });
        }
        var layer = comp.layers[layerIndex];
         if (!layer) {
            return JSON.stringify({ success: false, message: "Layer not found at index " + layerIndex + " in composition '" + comp.name + "'"});
        }

        var property;
        var propertyLabel;
        if (args.propertyPath && args.propertyPath.length) {
            var resolved = resolvePropertyPath(layer, args.propertyPath);
            if (resolved.error) return JSON.stringify({ success: false, message: resolved.error });
            property = resolved.property;
            propertyLabel = args.propertyPath.join(" > ");
        } else {
            var transformGroup = layer.property("Transform");

            property = transformGroup ? transformGroup.property(propertyName) : null;
             if (!property) {
                 if (layer.property("Effects") && layer.property("Effects").property(propertyName)) {
                     property = layer.property("Effects").property(propertyName);
                 } else if (layer.property("Text") && layer.property("Text").property(propertyName)) {
                     property = layer.property("Text").property(propertyName);
                 }

                // Search inside individual effects for sub-properties
                if (!property && layer.property("Effects")) {
                    var effects = layer.property("Effects");
                    for (var ei = 1; ei <= effects.numProperties; ei++) {
                        var eff = effects.property(ei);
                        try {
                            var subProp = eff.property(propertyName);
                            if (subProp) { property = subProp; break; }
                        } catch (e2) {}
                    }
                }

                if (!property) {
                     return JSON.stringify({ success: false, message: "Property '" + propertyName + "' not found on layer '" + layer.name + "'." });
                }
            }
            propertyLabel = propertyName;
        }

        if (!property.canSetExpression) {
            return JSON.stringify({ success: false, message: "Property '" + propertyLabel + "' does not support expressions." });
        }

        property.expression = expressionString;

        var action = expressionString === "" ? "removed" : "set";
        return JSON.stringify({ success: true, message: "Expression " + action + " for '" + propertyLabel + "' on layer '" + layer.name + "'." });
    } catch (e) {
        return JSON.stringify({ success: false, message: "Error setting expression: " + e.toString() + " (Line: " + e.line + ")" });
    }
}

// Full, untruncated expression text for one property — get-layer-tree truncates long
// expressions for context-efficiency; this is the drill-down when an agent needs the
// whole thing instead of falling back to raw run-jsx.
function getExpression(args) {
    try {
        var r = resolveLayerAndProperty(args);
        if (r.error) return JSON.stringify({ success: false, message: r.error });
        var expr = "";
        try { expr = r.property.expression || ""; } catch (e) {}
        var hasError = false;
        try { hasError = !!r.property.expressionError; } catch (e2) {}
        return JSON.stringify({
            success: true,
            layer: r.layer.name,
            propertyPath: r.propertyLabel,
            expression: expr,
            expressionEnabled: !!r.property.expressionEnabled,
            expressionError: hasError ? r.property.expressionError : null
        });
    } catch (e) {
        return JSON.stringify({ success: false, message: "Error reading expression: " + e.toString() + " (Line: " + e.line + ")" });
    }
}

// Batch expression edits in one round trip. Each edit is isolated in its own
// try/catch so one bad propertyPath/expression doesn't abort the rest of the batch
// (feedback: 4 separate setLayerExpression calls for one conceptual edit).
function setExpressions(args) {
    var edits = args.edits || [];
    var results = [];
    for (var i = 0; i < edits.length; i++) {
        var edit = edits[i];
        try {
            var r = resolveLayerAndProperty(edit);
            if (r.error) { results.push({ index: i, success: false, message: r.error }); continue; }
            if (!r.property.canSetExpression) {
                results.push({ index: i, success: false, message: "Property '" + r.propertyLabel + "' does not support expressions." });
                continue;
            }
            r.property.expression = edit.expression || "";
            results.push({ index: i, success: true, layer: r.layer.name, propertyPath: r.propertyLabel });
        } catch (e) {
            results.push({ index: i, success: false, message: "Error setting expression: " + e.toString() + " (Line: " + e.line + ")" });
        }
    }
    return JSON.stringify({ success: results.length > 0 && results.every(function (r) { return r.success; }), results: results });
}

// Evaluate a property's value at a given (or current) time without hand-rolling
// run-jsx for it. No temp-value-then-restore: setValueAtTime on a property with no
// keyframes creates one, so "poke and restore" leaves a stray keyframe behind on
// exactly the properties an agent is most likely to probe. run-jsx remains the
// escape hatch for that workflow.
function evaluateProperty(args) {
    try {
        var r = resolveLayerAndProperty(args);
        if (r.error) return JSON.stringify({ success: false, message: r.error });
        var evalTime = (args.time !== undefined) ? args.time : r.comp.time;
        var value = r.property.valueAtTime(evalTime, false);
        return JSON.stringify({
            success: true,
            layer: r.layer.name,
            propertyPath: r.propertyLabel,
            time: evalTime,
            value: value
        });
    } catch (e) {
        return JSON.stringify({ success: false, message: "Error evaluating property: " + e.toString() + " (Line: " + e.line + ")" });
    }
}

// ---- bridge-lib/effects.jsx ----
// Effect apply/remove/rename/enable/template commands, plus getEffectPropertiesByMatchName
// (matchName lookup via a throwaway scratch solid).
// Depends on resolveComp/listEffectProperties from utils.jsx.

// --- applyEffect (from applyEffect.jsx) ---
function applyEffect(args) {
    try {
        var layerIndex = args.layerIndex || 1; // Default to first layer
        var effectName = args.effectName; // Name of the effect to apply
        var effectMatchName = args.effectMatchName; // After Effects internal name (more reliable)
        var effectCategory = args.effectCategory || ""; // Optional category for filtering
        var presetPath = args.presetPath; // Optional path to an effect preset
        var effectSettings = args.effectSettings || {}; // Optional effect parameters

        if (!effectName && !effectMatchName && !presetPath) {
            throw new Error("You must specify either effectName, effectMatchName, or presetPath");
        }

        var comp = resolveComp(args);
        if (!comp) {
            throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        }

        var layer = comp.layer(layerIndex);
        if (!layer) {
            throw new Error("Layer not found at index " + layerIndex + " in composition '" + comp.name + "'");
        }

        var effectResult;

        if (presetPath) {
            var presetFile = new File(presetPath);
            if (!presetFile.exists) {
                throw new Error("Effect preset file not found: " + presetPath);
            }

            layer.applyPreset(presetFile);
            effectResult = {
                type: "preset",
                name: presetPath.split('/').pop().split('\\').pop(),
                applied: true
            };
        }
        else if (effectMatchName) {
            var effect = layer.Effects.addProperty(effectMatchName);
            applyEffectSettings(effect, effectSettings);
            effectResult = {
                type: "effect",
                name: effect.name,
                matchName: effect.matchName,
                index: effect.propertyIndex,
                properties: listEffectProperties(effect)
            };
        }
        else {
            var effect = layer.Effects.addProperty(effectName);
            applyEffectSettings(effect, effectSettings);
            effectResult = {
                type: "effect",
                name: effect.name,
                matchName: effect.matchName,
                index: effect.propertyIndex,
                properties: listEffectProperties(effect)
            };
        }

        return JSON.stringify({
            status: "success",
            message: "Effect applied successfully",
            effect: effectResult,
            layer: {
                name: layer.name,
                index: layerIndex
            },
            composition: {
                name: comp.name,
                id: comp.id
            }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({
            status: "error",
            message: error.toString()
        }, null, 2);
    }
}

// Lightweight "what effects does this layer already have" check — name/matchName/
// index/enabled per effect, no property dump. Cheaper than getLayerTree when all the
// agent needs is presence/order of the effect stack.
function listLayerEffects(args) {
    try {
        var layerIndex = args.layerIndex || 1;
        var comp = resolveComp(args);
        if (!comp) throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        var layer = comp.layer(layerIndex);
        if (!layer) throw new Error("Layer not found at index " + layerIndex + " in composition '" + comp.name + "'");

        var effects = layer.property("ADBE Effect Parade");
        var out = [];
        if (effects) {
            for (var i = 1; i <= effects.numProperties; i++) {
                var fx = effects.property(i);
                out.push({ index: i, name: fx.name, matchName: fx.matchName, enabled: fx.enabled });
            }
        }
        return JSON.stringify({
            status: "success",
            composition: comp.name,
            layer: { name: layer.name, index: layerIndex },
            effects: out
        }, null, 2);
    } catch (error) {
        return JSON.stringify({ status: "error", message: error.toString() }, null, 2);
    }
}

// Flat property list (index, name, matchName, value, valueType) for an effect already
// applied to a layer, identified by effectIndex/effectName/effectMatchName. Effects can
// have multiple properties sharing the same display name (e.g. Grid's own "Width" vs. a
// Feather sub-group's "Width") — effect("Name")("Name") in expressions/run-jsx silently
// grabs the first match, which can be the wrong one. Use the returned index or matchName
// (both unambiguous) instead of the display name to address the intended property.
function getLayerEffectProperties(args) {
    try {
        var layerIndex = args.layerIndex || 1;
        var comp = resolveComp(args);
        if (!comp) throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        var layer = comp.layer(layerIndex);
        if (!layer) throw new Error("Layer not found at index " + layerIndex + " in composition '" + comp.name + "'");

        var effects = layer.property("ADBE Effect Parade");
        if (!effects || effects.numProperties === 0) throw new Error("Layer '" + layer.name + "' has no effects");

        var target = null;
        if (args.effectIndex) {
            target = effects.property(args.effectIndex);
        } else if (args.effectMatchName) {
            for (var i = 1; i <= effects.numProperties; i++) {
                if (effects.property(i).matchName === args.effectMatchName) { target = effects.property(i); break; }
            }
        } else if (args.effectName) {
            for (var j = 1; j <= effects.numProperties; j++) {
                if (effects.property(j).name === args.effectName) { target = effects.property(j); break; }
            }
        } else {
            throw new Error("Specify effectName, effectMatchName, or effectIndex");
        }
        if (!target) throw new Error("Effect not found on layer '" + layer.name + "'");

        return JSON.stringify({
            status: "success",
            layer: { name: layer.name, index: layerIndex },
            effect: { name: target.name, matchName: target.matchName, index: target.propertyIndex },
            properties: listEffectProperties(target)
        }, null, 2);
    } catch (e) {
        return JSON.stringify({ status: "error", message: e.toString() }, null, 2);
    }
}

// Remove an effect from a layer, identified by effectName, effectMatchName, or
// 1-based effectIndex (within the layer's effect stack).
function removeEffect(args) {
    try {
        var layerIndex = args.layerIndex || 1;
        var comp = resolveComp(args);
        if (!comp) throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        var layer = comp.layer(layerIndex);
        if (!layer) throw new Error("Layer not found at index " + layerIndex + " in composition '" + comp.name + "'");

        var effects = layer.property("ADBE Effect Parade");
        if (!effects || effects.numProperties === 0) throw new Error("Layer '" + layer.name + "' has no effects");

        var target = null;
        if (args.effectIndex) {
            target = effects.property(args.effectIndex);
        } else if (args.effectMatchName) {
            for (var i = 1; i <= effects.numProperties; i++) {
                if (effects.property(i).matchName === args.effectMatchName) { target = effects.property(i); break; }
            }
        } else if (args.effectName) {
            for (var j = 1; j <= effects.numProperties; j++) {
                if (effects.property(j).name === args.effectName) { target = effects.property(j); break; }
            }
        } else {
            throw new Error("Specify effectName, effectMatchName, or effectIndex");
        }
        if (!target) throw new Error("Effect not found on layer '" + layer.name + "'");

        var removed = target.name;
        app.beginUndoGroup("Remove effect");
        target.remove();
        app.endUndoGroup();

        var remaining = [];
        for (var k = 1; k <= effects.numProperties; k++) remaining.push(effects.property(k).name);
        return JSON.stringify({
            status: "success",
            message: "Removed effect '" + removed + "' from '" + layer.name + "'",
            layer: { name: layer.name, index: layerIndex },
            composition: { name: comp.name, id: comp.id },
            remainingEffects: remaining
        }, null, 2);
    } catch (e) {
        return JSON.stringify({ status: "error", message: e.toString() }, null, 2);
    }
}

function renameEffect(args) {
    try {
        var comp = resolveComp(args);
        if (!comp) throw new Error("Composition not found");
        var layer = comp.layer(args.layerIndex || 1);
        if (!layer) throw new Error("Layer not found");
        var effects = layer.property("ADBE Effect Parade");
        var target = null;
        if (args.effectIndex) {
            target = effects.property(args.effectIndex);
        } else if (args.effectName) {
            for (var i = 1; i <= effects.numProperties; i++) {
                if (effects.property(i).name === args.effectName) { target = effects.property(i); break; }
            }
        } else if (args.effectMatchName) {
            for (var j = 1; j <= effects.numProperties; j++) {
                if (effects.property(j).matchName === args.effectMatchName) { target = effects.property(j); break; }
            }
        }
        if (!target) throw new Error("Effect not found");
        if (!args.newName) throw new Error("newName is required");
        app.beginUndoGroup("Rename effect");
        target.name = args.newName;
        app.endUndoGroup();
        return JSON.stringify({ status: "success", message: "Renamed effect to '" + target.name + "'", composition: { name: comp.name, id: comp.id } });
    } catch (e) {
        return JSON.stringify({ status: "error", message: e.toString() });
    }
}

function setEffectEnabled(args) {
    try {
        var comp = resolveComp(args);
        if (!comp) throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        var layer = comp.layer(args.layerIndex || 1);
        if (!layer) throw new Error("Layer not found");
        var effects = layer.property("ADBE Effect Parade");
        if (!effects || effects.numProperties === 0) throw new Error("Layer '" + layer.name + "' has no effects");

        var target = null;
        if (args.effectIndex) {
            target = effects.property(args.effectIndex);
        } else if (args.effectMatchName) {
            for (var i = 1; i <= effects.numProperties; i++) {
                if (effects.property(i).matchName === args.effectMatchName) { target = effects.property(i); break; }
            }
        } else if (args.effectName) {
            for (var j = 1; j <= effects.numProperties; j++) {
                if (effects.property(j).name === args.effectName) { target = effects.property(j); break; }
            }
        } else {
            throw new Error("Specify effectName, effectMatchName, or effectIndex");
        }
        if (!target) throw new Error("Effect not found on layer '" + layer.name + "'");
        if (args.enabled === undefined) throw new Error("enabled (true/false) is required");

        app.beginUndoGroup("Toggle effect enabled");
        target.enabled = !!args.enabled;
        app.endUndoGroup();

        return JSON.stringify({
            status: "success",
            message: (target.enabled ? "Enabled" : "Disabled") + " effect '" + target.name + "' on '" + layer.name + "'",
            layer: { name: layer.name, index: args.layerIndex || 1 },
            effect: { name: target.name, enabled: target.enabled },
            composition: { name: comp.name, id: comp.id }
        }, null, 2);
    } catch (e) {
        return JSON.stringify({ status: "error", message: e.toString() }, null, 2);
    }
}

// Helper function to apply effect settings
function applyEffectSettings(effect, settings) {
    if (!settings) return;
    var hasKeys = false;
    for (var k in settings) { if (settings.hasOwnProperty(k)) { hasKeys = true; break; } }
    if (!hasKeys) return;

    for (var propName in settings) {
        if (settings.hasOwnProperty(propName)) {
            try {
                var property = null;

                try {
                    property = effect.property(propName);
                } catch (e) {
                    for (var i = 1; i <= effect.numProperties; i++) {
                        var prop = effect.property(i);
                        if (prop.name === propName) {
                            property = prop;
                            break;
                        }
                    }
                }

                // Set the property. An object value { parameters, value } lets the caller
                // set a Dropdown Menu Control's items via setPropertyParameters and/or a
                // default value; a plain value is set directly.
                var val = settings[propName];
                if (property && val && typeof val === "object" && !(val instanceof Array) &&
                    (val.parameters !== undefined || val.value !== undefined)) {
                    if (val.parameters && property.setPropertyParameters) {
                        property.setPropertyParameters(val.parameters);
                    }
                    if (val.value !== undefined && property.setValue) {
                        property.setValue(val.value);
                    }
                } else if (property && property.setValue) {
                    property.setValue(val);
                }
            } catch (e) {
                $.writeln("Error setting effect property '" + propName + "': " + e.toString());
            }
        }
    }
}

// --- applyEffectTemplate (from applyEffectTemplate.jsx) ---
function applyEffectTemplate(args) {
    try {
        var layerIndex = args.layerIndex || 1; // Default to first layer
        var templateName = args.templateName; // Name of the template to apply
        var customSettings = args.customSettings || {}; // Optional customizations

        if (!templateName) {
            throw new Error("You must specify a templateName");
        }

        var comp = resolveComp(args);
        if (!comp) {
            throw new Error("Composition not found (pass compName or compIndex, or open a comp)");
        }

        var layer = comp.layer(layerIndex);
        if (!layer) {
            throw new Error("Layer not found at index " + layerIndex + " in composition '" + comp.name + "'");
        }

        // Template definitions
        var templates = {
            // Blur effects
            "gaussian-blur": {
                effectMatchName: "ADBE Gaussian Blur 2",
                settings: {
                    "Blurriness": customSettings.blurriness || 20
                }
            },
            "directional-blur": {
                effectMatchName: "ADBE Directional Blur",
                settings: {
                    "Direction": customSettings.direction || 0,
                    "Blur Length": customSettings.length || 10
                }
            },

            // Color correction effects
            "color-balance": {
                effectMatchName: "ADBE Color Balance (HLS)",
                settings: {
                    "Hue": customSettings.hue || 0,
                    "Lightness": customSettings.lightness || 0,
                    "Saturation": customSettings.saturation || 0
                }
            },
            "brightness-contrast": {
                effectMatchName: "ADBE Brightness & Contrast 2",
                settings: {
                    "Brightness": customSettings.brightness || 0,
                    "Contrast": customSettings.contrast || 0,
                    "Use Legacy": false
                }
            },
            "curves": {
                effectMatchName: "ADBE CurvesCustom"
                // Curves are complex and would need special handling
            },

            // Stylistic effects
            "glow": {
                effectMatchName: "ADBE Glow",
                settings: {
                    "Glow Threshold": customSettings.threshold || 50,
                    "Glow Radius": customSettings.radius || 15,
                    "Glow Intensity": customSettings.intensity || 1
                }
            },
            "drop-shadow": {
                effectMatchName: "ADBE Drop Shadow",
                settings: {
                    "Shadow Color": customSettings.color || [0, 0, 0, 1],
                    "Opacity": customSettings.opacity || 50,
                    "Direction": customSettings.direction || 135,
                    "Distance": customSettings.distance || 10,
                    "Softness": customSettings.softness || 10
                }
            },

            // Common effect chains
            "cinematic-look": {
                effects: [
                    {
                        effectMatchName: "ADBE CurvesCustom",
                        settings: {}
                    },
                    {
                        effectMatchName: "ADBE Vibrance",
                        settings: {
                            "Vibrance": 15,
                            "Saturation": -5
                        }
                    }
                ]
            },
            "text-pop": {
                effects: [
                    {
                        effectMatchName: "ADBE Drop Shadow",
                        settings: {
                            "Shadow Color": [0, 0, 0, 1],
                            "Opacity": 75,
                            "Distance": 5,
                            "Softness": 10
                        }
                    },
                    {
                        effectMatchName: "ADBE Glow",
                        settings: {
                            "Glow Threshold": 50,
                            "Glow Radius": 10,
                            "Glow Intensity": 1.5
                        }
                    }
                ]
            }
        };

        var template = templates[templateName];
        if (!template) {
            // No Object.keys in ExtendScript's ES3 engine.
            var availableTemplates = [];
            for (var templateKey in templates) {
                if (templates.hasOwnProperty(templateKey)) availableTemplates.push(templateKey);
            }
            throw new Error("Template '" + templateName + "' not found. Available templates: " + availableTemplates.join(", "));
        }

        var appliedEffects = [];

        if (template.effectMatchName) {
            var effect = layer.Effects.addProperty(template.effectMatchName);

            for (var propName in template.settings) {
                try {
                    var property = effect.property(propName);
                    if (property) {
                        property.setValue(template.settings[propName]);
                    }
                } catch (e) {
                    $.writeln("Warning: Could not set " + propName + " on effect " + effect.name + ": " + e);
                }
            }

            appliedEffects.push({
                name: effect.name,
                matchName: effect.matchName
            });
        } else if (template.effects) {
            for (var i = 0; i < template.effects.length; i++) {
                var effectData = template.effects[i];
                var effect = layer.Effects.addProperty(effectData.effectMatchName);

                for (var propName in effectData.settings) {
                    try {
                        var property = effect.property(propName);
                        if (property) {
                            property.setValue(effectData.settings[propName]);
                        }
                    } catch (e) {
                        $.writeln("Warning: Could not set " + propName + " on effect " + effect.name + ": " + e);
                    }
                }

                appliedEffects.push({
                    name: effect.name,
                    matchName: effect.matchName
                });
            }
        }

        return JSON.stringify({
            status: "success",
            message: "Effect template '" + templateName + "' applied successfully",
            appliedEffects: appliedEffects,
            layer: {
                name: layer.name,
                index: layerIndex
            },
            composition: {
                name: comp.name,
                id: comp.id
            }
        }, null, 2);
    } catch (error) {
        return JSON.stringify({
            status: "error",
            message: error.toString()
        }, null, 2);
    }
}

// List an effect's properties (name/matchName/index/type/expected value shape) by
// matchName alone — no layer needs to carry the effect already. Applies it to a
// scratch solid created (and removed) within this call, so it's a one-shot lookup
// instead of the "apply, dump, guess again, remove" round-trip agents were doing.
// Wrapped in an undo group so any mid-flight failure is one Ctrl+Z away.
function getEffectPropertiesByMatchName(args) {
    var matchName = args.matchName, effectName = args.effectName;
    if (!matchName && !effectName) return JSON.stringify({ success: false, message: "Pass matchName (preferred) or effectName." });
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ success: false, message: "Composition not found (pass compName or compIndex, or open a comp)." });
    var scratchLayer = null;
    app.beginUndoGroup("MCP effect inspect");
    try {
        scratchLayer = comp.layers.addSolid([0, 0, 0], "__mcp_scratch__", comp.width, comp.height, 1, 0.1);
        var effect = scratchLayer.Effects.addProperty(matchName || effectName);
        var props = listEffectProperties(effect);
        return JSON.stringify({
            success: true,
            name: effect.name,
            matchName: effect.matchName,
            properties: props
        });
    } catch (e) {
        return JSON.stringify({ success: false, message: "Error inspecting effect '" + (matchName || effectName) + "': " + e.toString() + " (Line: " + e.line + ")" });
    } finally {
        // addSolid creates a Solids-folder project item in addition to the layer;
        // removing only the layer leaves that source item orphaned permanently.
        if (scratchLayer) {
            try {
                var src = scratchLayer.source;
                scratchLayer.remove();
                if (src) src.remove();
            } catch (eRm) {}
        }
        app.endUndoGroup();
    }
}

// ---- bridge-lib/viewport.jsx ----
// Viewport fit/zoom helpers for get-viewport-screenshot. Depends on resolveComp (utils.jsx).

// Zoom the comp's viewer to "Fit up to 100%" before an OS-level screenshot, so the
// capture shows the framed comp centered instead of whatever pan/zoom was left over
// from manual work. Returns the pre-existing zoom so the caller can restore it.
function prepareViewportCapture(args) {
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ status: "error", message: "No composition found (pass compName, or make a comp active)." });
    try {
        if (typeof args.time === "number") comp.time = args.time;
        var viewer = comp.openInViewer();
        if (!viewer) return JSON.stringify({ status: "error", message: "Could not open composition '" + comp.name + "' in viewer." });
        var view = viewer.views[viewer.activeViewIndex];
        var savedZoom = view.options.zoom;
        // ponytail: known ceiling — fit-to-view reliably no-ops (root cause believed to be
        // OS-level window focus: executeCommand for panel-scoped commands needs real UI
        // focus, which a script fired from the bridge's idle poll task never has — see git
        // history for the fuller investigation). It doesn't affect the screenshot quality,
        // so this is now best-effort: try, and if it doesn't stick, proceed anyway instead
        // of reporting an error the agent has no useful action to take on.
        try {
            var candidates = ["Fit", "Fit up to 100%", "Fit Up to 100%"];
            var cmdId = 0;
            for (var ci = 0; ci < candidates.length; ci++) {
                cmdId = app.findMenuCommandId(candidates[ci]);
                if (cmdId) break;
            }
            if (cmdId) app.executeCommand(cmdId);
        } catch (fitErr) {}
        return JSON.stringify({
            status: "success",
            compName: comp.name,
            savedZoom: savedZoom,
            time: comp.time,
            projectFile: app.project.file ? app.project.file.name : "Untitled Project"
        });
    } catch (e) {
        return JSON.stringify({ status: "error", message: "prepareViewportCapture failed: " + e.toString() });
    }
}

// Companion to prepareViewportCapture — restores the zoom saved before the fit-to-view
// so a screenshot doesn't leave the user's own pan/zoom disturbed.
function restoreViewportZoom(args) {
    var comp = resolveComp(args);
    if (!comp) return JSON.stringify({ status: "error", message: "No composition found." });
    if (typeof args.zoom !== "number") return JSON.stringify({ status: "error", message: "No zoom value provided to restore." });
    try {
        var viewer = comp.openInViewer();
        if (!viewer) return JSON.stringify({ status: "error", message: "Could not open composition '" + comp.name + "' in viewer." });
        var view = viewer.views[viewer.activeViewIndex];
        view.options.zoom = args.zoom;
        return JSON.stringify({ status: "success" });
    } catch (e) {
        return JSON.stringify({ status: "error", message: "restoreViewportZoom failed: " + e.toString() });
    }
}

// ---- bridge-lib/jsx-runner.jsx ----
// Generic escape hatch (runJsx) and installed-script discovery (listInstalledScripts).

// Generic escape hatch: execute raw ExtendScript (args.code) or a .jsx file (args.filePath).
// Wraps in an undo group and captures thrown errors with line numbers so the agent
// can debug scripts it writes on the fly instead of relying on bespoke per-feature tools.
function runJsx(args) {
    args = args || {};
    var code = args.code;
    var sourceLabel = "inline code";
    if (!code && args.filePath) {
        var f = new File(args.filePath);
        if (!f.exists) return JSON.stringify({ status: "error", message: "File not found: " + args.filePath });
        f.encoding = "UTF-8";
        f.open("r");
        code = f.read();
        f.close();
        sourceLabel = args.filePath;
    }
    if (!code) return JSON.stringify({ status: "error", message: "Provide either 'code' (raw ExtendScript) or 'filePath' (.jsx file)." });

    app.beginUndoGroup("MCP runJsx: " + sourceLabel);
    try {
        var evalResult = eval(code);
        app.endUndoGroup();

        var serialized = null;
        var note;
        if (evalResult === undefined) {
            note = "script returned undefined (no trailing expression)";
        } else {
            try {
                JSON.stringify(evalResult); // throws on circular refs / AE objects
                serialized = evalResult;
            } catch (serErr) {
                serialized = String(evalResult);
            }
        }

        var envelope = { status: "success", source: sourceLabel, result: serialized };
        if (note) envelope.note = note;
        var resultStr = JSON.stringify(envelope, null, 2);
        if (resultStr.length > 100000) {
            resultStr = JSON.stringify({ status: "success", source: sourceLabel, result: "[truncated: result exceeded 100KB]" }, null, 2);
        }
        return resultStr;
    } catch (e) {
        app.endUndoGroup();
        return JSON.stringify({ status: "error", source: sourceLabel, message: e.message || e.toString(), line: e.line || null });
    }
}

// List .jsx/.jsxbin scripts installed under the AE app folder so the agent can see
// what's already available (e.g. a user's own ScriptUI panel) before writing its own.
function listInstalledScripts() {
    var result = { scriptsFolder: [], scriptUIPanels: [] };

    function listDir(dir) {
        var out = [];
        if (dir.exists) {
            var files = dir.getFiles(function (f) {
                return f instanceof File && /\.(jsx|jsxbin)$/i.test(f.name);
            });
            for (var i = 0; i < files.length; i++) {
                out.push({
                    name: files[i].name,
                    path: files[i].fsName,
                    type: /\.jsxbin$/i.test(files[i].name) ? "compiled" : "source"
                });
            }
        }
        return out;
    }

    var base = new Folder(app.path.fsName);
    result.scriptsFolder = listDir(new Folder(base.fsName + "/Scripts"));
    result.scriptUIPanels = listDir(new Folder(base.fsName + "/Scripts/ScriptUI Panels"));
    return JSON.stringify(result, null, 2);
}

// ---- bridge-lib/command-io.jsx ----
// Command-file dispatch: reads ae_command.json, routes to the right handler function,
// writes ae_mcp_result.json. Depends on logToPanel/setStatus (defined in the main panel
// file) and getAmbientContext/toISOStringCompat (utils.jsx), plus every domain handler.

// Command file path - use Documents folder for reliable access
function getCommandFilePath() {
    var userFolder = Folder.myDocuments;
    var bridgeFolder = new Folder(userFolder.fsName + "/ae-mcp-bridge");
    if (!bridgeFolder.exists) {
        bridgeFolder.create();
    }
    return bridgeFolder.fsName + "/ae_command.json";
}

// Result file path - use Documents folder for reliable access
function getResultFilePath() {
    var userFolder = Folder.myDocuments;
    var bridgeFolder = new Folder(userFolder.fsName + "/ae-mcp-bridge");
    if (!bridgeFolder.exists) {
        bridgeFolder.create();
    }
    return bridgeFolder.fsName + "/ae_mcp_result.json";
}

// Execute command
function executeCommand(command, args, expectedTimestamp) {
    var result = "";

    logToPanel("Executing command: " + command);
    setStatus("Running: " + command);
    try { panel.update(); } catch (e) {}

    try {
        logToPanel("Attempting to execute: " + command); // Log before switch
        switch (command) {
            case "ping":
                // Pure liveness check - no project/comp/layer access, so it works
                // even when nothing is open, and confirms the poll loop is running.
                result = JSON.stringify({ status: "ok", alive: true, version: __BRIDGE_VERSION });
                break;
            case "getProjectInfo":
                result = getProjectInfo();
                break;
            case "listCompositions":
                result = listCompositions();
                break;
            case "getCompositionInfo":
                result = getCompositionInfo(args);
                break;
            case "getLayerInfo":
                result = getLayerInfo(args);
                break;
            case "getLayerTree":
                result = getLayerTree(args);
                break;
            case "prepareViewportCapture":
                result = prepareViewportCapture(args);
                break;
            case "restoreViewportZoom":
                result = restoreViewportZoom(args);
                break;
            case "duplicateComp":
                result = duplicateComp(args);
                break;
            case "createComposition":
                logToPanel("Calling createComposition function...");
                result = createComposition(args);
                logToPanel("Returned from createComposition.");
                break;
            case "createTextLayer":
                logToPanel("Calling createTextLayer function...");
                result = createTextLayer(args);
                logToPanel("Returned from createTextLayer.");
                break;
            case "createShapeLayer":
                logToPanel("Calling createShapeLayer function...");
                result = createShapeLayer(args);
                logToPanel("Returned from createShapeLayer. Result type: " + typeof result);
                break;
            case "createSolidLayer":
                logToPanel("Calling createSolidLayer function...");
                result = createSolidLayer(args);
                logToPanel("Returned from createSolidLayer.");
                break;
            case "setLayerProperties":
                logToPanel("Calling setLayerProperties function...");
                result = setLayerProperties(args);
                logToPanel("Returned from setLayerProperties.");
                break;
            case "setLayerKeyframe":
                logToPanel("Calling setLayerKeyframe function...");
                result = setLayerKeyframe(args);
                logToPanel("Returned from setLayerKeyframe.");
                break;
            case "setLayerExpression":
                logToPanel("Calling setLayerExpression function...");
                result = setLayerExpression(args);
                logToPanel("Returned from setLayerExpression.");
                break;
            case "getExpression":
                result = getExpression(args);
                break;
            case "setExpressions":
                result = setExpressions(args);
                break;
            case "evaluateProperty":
                result = evaluateProperty(args);
                break;
            case "getEffectPropertiesByMatchName":
                result = getEffectPropertiesByMatchName(args);
                break;
            case "listLayerEffects":
                result = listLayerEffects(args);
                break;
            case "getLayerEffectProperties":
                result = getLayerEffectProperties(args);
                break;
            case "applyEffect":
                logToPanel("Calling applyEffect function...");
                result = applyEffect(args);
                logToPanel("Returned from applyEffect.");
                break;
            case "removeEffect":
                logToPanel("Calling removeEffect function...");
                result = removeEffect(args);
                logToPanel("Returned from removeEffect.");
                break;
            case "renameEffect":
                logToPanel("Calling renameEffect function...");
                result = renameEffect(args);
                logToPanel("Returned from renameEffect.");
                break;
            case "setEffectEnabled":
                logToPanel("Calling setEffectEnabled function...");
                result = setEffectEnabled(args);
                logToPanel("Returned from setEffectEnabled.");
                break;
            case "applyEffectTemplate":
                logToPanel("Calling applyEffectTemplate function...");
                result = applyEffectTemplate(args);
                logToPanel("Returned from applyEffectTemplate.");
                break;
            case "createCamera":
                logToPanel("Calling createCamera function...");
                result = createCamera(args);
                logToPanel("Returned from createCamera.");
                break;
            case "batchSetLayerProperties":
                logToPanel("Calling batchSetLayerProperties function...");
                result = batchSetLayerProperties(args);
                logToPanel("Returned from batchSetLayerProperties.");
                break;
            case "setCompositionProperties":
                logToPanel("Calling setCompositionProperties function...");
                result = setCompositionProperties(args);
                logToPanel("Returned from setCompositionProperties.");
                break;
            case "duplicateLayer":
                logToPanel("Calling duplicateLayer function...");
                result = duplicateLayer(args);
                logToPanel("Returned from duplicateLayer.");
                break;
            case "deleteLayer":
                logToPanel("Calling deleteLayer function...");
                result = deleteLayer(args);
                logToPanel("Returned from deleteLayer.");
                break;
            case "setLayerMask":
                logToPanel("Calling setLayerMask function...");
                result = setLayerMask(args);
                logToPanel("Returned from setLayerMask.");
                break;
            case "runJsx":
                logToPanel("Calling runJsx function...");
                result = runJsx(args);
                logToPanel("Returned from runJsx.");
                break;
            case "listInstalledScripts":
                logToPanel("Calling listInstalledScripts function...");
                result = listInstalledScripts();
                logToPanel("Returned from listInstalledScripts.");
                break;
            default:
                result = JSON.stringify({ error: "Unknown command: " + command });
        }
        logToPanel("Execution finished for: " + command); // Log after switch

        // Save the result (ensure result is always a string)
        logToPanel("Preparing to write result file...");
        var resultString = (typeof result === 'string') ? result : JSON.stringify(result);

        // Try to parse the result as JSON to add a timestamp
        try {
            var resultObj = JSON.parse(resultString);
            resultObj._responseTimestamp = toISOStringCompat(new Date());
            resultObj._commandExecuted = command;
            // Echoes the command file's own timestamp back so Node can match this result to
            // THIS specific request rather than any past-or-future result sharing the same
            // command name (e.g. two rapid runJsx calls where the first timed out client-side
            // but AE finishes it after the second has already been queued).
            resultObj._requestId = expectedTimestamp;
            resultObj.context = getAmbientContext();
            resultString = JSON.stringify(resultObj, null, 2);
            logToPanel("Added timestamp to result JSON for tracking freshness.");
        } catch (parseError) {
            logToPanel("Could not parse result as JSON to add timestamp: " + parseError.toString());
        }

        var resultFile = new File(getResultFilePath());
        resultFile.encoding = "UTF-8"; // Ensure UTF-8 encoding
        logToPanel("Opening result file for writing...");
        var opened = resultFile.open("w");
        if (!opened) {
            logToPanel("ERROR: Failed to open result file for writing: " + resultFile.fsName);
            throw new Error("Failed to open result file for writing.");
        }
        logToPanel("Writing to result file...");
        var written = resultFile.write(resultString);
        if (!written) {
             logToPanel("ERROR: Failed to write to result file (write returned false): " + resultFile.fsName);
        }
        logToPanel("Closing result file...");
        var closed = resultFile.close();
         if (!closed) {
             logToPanel("ERROR: Failed to close result file: " + resultFile.fsName);
        }
        logToPanel("Result file write process complete.");

        logToPanel("Command completed successfully: " + command);
        setStatus("Command completed: " + command);

        logToPanel("Updating command status to completed...");
        updateCommandStatus("completed", expectedTimestamp);
        logToPanel("Command status updated.");

    } catch (error) {
        var errorMsg = "ERROR in executeCommand for '" + command + "': " + error.toString() + (error.line ? " (line: " + error.line + ")" : "");
        logToPanel(errorMsg); // Log detailed error
        setStatus("Error: " + error.toString());

        try {
            logToPanel("Attempting to write ERROR to result file...");
            var errorResult = JSON.stringify({
                status: "error",
                command: command,
                message: error.toString(),
                line: error.line,
                fileName: error.fileName,
                _responseTimestamp: toISOStringCompat(new Date()),
                _commandExecuted: command,
                _requestId: expectedTimestamp,
                context: getAmbientContext()
            });
            var errorFile = new File(getResultFilePath());
            errorFile.encoding = "UTF-8";
            if (errorFile.open("w")) {
                errorFile.write(errorResult);
                errorFile.close();
                logToPanel("Successfully wrote ERROR to result file.");
            } else {
                 logToPanel("CRITICAL ERROR: Failed to open result file to write error!");
            }
        } catch (writeError) {
             logToPanel("CRITICAL ERROR: Failed to write error to result file: " + writeError.toString());
        }

        logToPanel("Updating command status to error...");
        updateCommandStatus("error", expectedTimestamp);
        logToPanel("Command status updated to error.");
    }
}

// Update command file status
// expectedTimestamp (when given) guards against clobbering a newer command: if Node
// wrote a fresh pending command while this one was still running (e.g. after a prior
// timeout), the file on disk no longer belongs to the run finishing now, and blindly
// stamping our status onto it would silently disappear that newer command's result.
function updateCommandStatus(status, expectedTimestamp) {
    try {
        var commandFile = new File(getCommandFilePath());
        if (commandFile.exists) {
            commandFile.open("r");
            var content = commandFile.read();
            commandFile.close();

            if (content) {
                var commandData = JSON.parse(content);
                if (expectedTimestamp && commandData.timestamp !== expectedTimestamp) {
                    logToPanel("Skipped status update - command file now holds a newer command.");
                    return;
                }
                commandData.status = status;

                commandFile.open("w");
                commandFile.write(JSON.stringify(commandData, null, 2));
                commandFile.close();
            }
        }
    } catch (e) {
        logToPanel("Error updating command status: " + e.toString());
    }
}

// ---- bridge-entry.jsx ----
// bridge-entry.jsx
// UI/polling half of the MCP Bridge panel. This file is NOT deployed directly —
// `npm run build` concatenates bridge-lib/*.jsx + this file into the generated
// "MCP Bridge.jsx", which is what actually gets copied to the AE install path.
// (An ExtendScript #include-based split was tried first and reverted: AE's
// reloadBridge()'s `$.evalFile` did not process #include directives the same way
// panel-open does — a live test left reloadBridge silently no-op'ing instead of
// picking up new code. Build-time concatenation gives identical runtime behavior
// to the old single-file bridge while still keeping the source small and modular.)

// Remember where AE loaded us from, and distinguish a code-only reload (our
// "Reload Panel" button re-evals this file) from a fresh panel open by AE. On a
// reload we refresh all the handler functions but skip rebuilding the UI /
// rescheduling the poller — so no second window and no double polling.
$.global.__mcpBridgeScriptFile = $.fileName;
var __mcpReloading = ($.global.__mcpBridgeReloading === true);
$.global.__mcpBridgeReloading = false;
var __BRIDGE_VERSION = "v3-split";

// Build the UI only on a real panel open (skip on a code-only reload — the
// existing widgets and their globals are reused).
if (!__mcpReloading) {
// Dockable when launched from the ScriptUI Panels folder (AE passes a Panel as `this`);
// falls back to a floating palette when run any other way. This is the canonical AE idiom.
var panel = (this instanceof Panel) ? this : new Window("palette", "MCP Bridge", undefined, {resizeable: true});
panel.orientation = "column";
panel.alignChildren = ["fill", "top"];
panel.spacing = 10;
panel.margins = 16;

// Status display
var statusText = panel.add("statictext", undefined, "Waiting for commands...");
statusText.alignment = ["fill", "top"];

// Add log area
var logPanel = panel.add("panel", undefined, "Command Log");
logPanel.orientation = "column";
logPanel.alignChildren = ["fill", "fill"];
var logText = logPanel.add("edittext", undefined, "", {multiline: true, readonly: true});
logText.preferredSize.height = 200;

// Auto-run checkbox
var autoRunCheckbox = panel.add("checkbox", undefined, "Auto-run commands");
autoRunCheckbox.value = true;

// Check interval (ms)
var checkInterval = 2000;
var isChecking = false;
// app.scheduleTask task id, so we can cancel a stale/duplicate schedule before
// re-arming (AE can silently drop the repeating task while a modal-ish UI
// state — e.g. the Timeline's inline expression editor — is active).
var scheduledTaskId = null;
// Updated at the top of every checkForCommands() run. onActivate below compares
// against this to notice a dead poller and self-heal without a manual click.
var lastPollAt = new Date().getTime();
}

// Log message to panel. logText can be transiently unavailable mid-reloadBridge()
// (the fresh $.evalFile pass skips UI rebuild but there's a brief window before
// this function itself is redefined) — never let a log call crash the command.
function logToPanel(message) {
    var timestamp = new Date().toLocaleTimeString();
    try {
        logText.text = timestamp + ": " + message + "\n" + logText.text;
    } catch (e) {}
}

// Same transient-unavailability risk as logToPanel, for the other UI widget commonly
// touched mid-command (see logToPanel's comment).
function setStatus(message) {
    try {
        statusText.text = message;
    } catch (e) {}
}

// Check for new commands
function checkForCommands() {
    try {
        if (!autoRunCheckbox.value || isChecking) return;
    } catch (e) {
        return; // autoRunCheckbox transiently unavailable (mid-reloadBridge) - skip this poll
    }

    isChecking = true;
    lastPollAt = new Date().getTime();
    var pollTime = new Date().toLocaleTimeString();

    // try/finally so isChecking ALWAYS gets reset, even if something in here
    // throws in a way the inner catch doesn't expect. A stuck isChecking=true
    // would silently no-op every future poll forever.
    try {
        try {
            var commandFile = new File(getCommandFilePath());
            var ranCommand = false;
            if (commandFile.exists) {
                commandFile.open("r");
                var content = commandFile.read();
                commandFile.close();

                if (content) {
                    var commandData = (typeof JSON !== "undefined" && JSON.parse)
                        ? JSON.parse(content)
                        : eval("(" + content + ")");

                    // Only execute pending commands
                    if (commandData.status === "pending") {
                        // Update status to running
                        updateCommandStatus("running", commandData.timestamp);

                        // Execute the command
                        executeCommand(commandData.command, commandData.args || {}, commandData.timestamp);
                        ranCommand = true;
                    }
                }
            }
            // Heartbeat: make it visually obvious in the panel that polling is
            // alive, instead of silently doing nothing when there's no command.
            if (!ranCommand) {
                setStatus("Waiting for commands... (last poll " + pollTime + ")");
            }
        } catch (e) {
            logToPanel("Error checking for commands: " + e.toString());
        }
    } finally {
        isChecking = false;
        // Re-arm the NEXT check as a fresh one-shot task rather than relying on
        // app.scheduleTask's own repeating mode. AE has been observed to silently
        // drop a repeating task and never resume it; a one-shot that reschedules
        // itself each time it actually runs has no persistent repeating task for
        // AE to drop in the first place.
        startCommandChecker();
    }
}

// Schedule the next checkForCommands() call. Cancels any previously-scheduled
// task first — belt-and-suspenders against stacking duplicate concurrent
// pollers (e.g. if both a self-rearm and a manual Force Check Now race).
function startCommandChecker() {
    if (scheduledTaskId !== null && scheduledTaskId !== undefined) {
        try { app.cancelTask(scheduledTaskId); } catch (e) {}
    }
    scheduledTaskId = app.scheduleTask("checkForCommands()", checkInterval, false);
}

// Runs checkForCommands() synchronously, right now, from a button click, AND
// re-arms the scheduled poll task. A manual click always reaches AE's event
// loop even when app.scheduleTask has stalled (e.g. AE suspended it during an
// expression-editor edit) — but the stalled task itself was never cancelled
// or rescheduled, so a plain one-off check here used to leave polling dead
// afterward. Re-arming makes this a real unstick, not just a single peek.
function forceCheckNow() {
    isChecking = false; // defensive: clear a stuck flag before forcing a check
    logToPanel("Force Check Now clicked.");
    startCommandChecker(); // cancel + re-arm the polling task
    checkForCommands();
}

// Re-eval this file from disk so edits to the handlers take effect without
// closing/reopening the panel. Sets a flag the fresh eval reads to skip UI rebuild.
// Also does a FULL reset of the poller and runs an immediate synchronous check
// (via forceCheckNow) so this button is a real reset, not just a code refresh.
function reloadBridge() {
    try {
        var f = new File($.global.__mcpBridgeScriptFile);
        if (!f.exists) { logToPanel("Reload failed - script not found: " + f.fsName); return; }
        logToPanel("Reloading handlers from " + f.fsName);
        $.global.__mcpBridgeReloading = true;
        $.evalFile(f);
        logToPanel("Reload complete.");
        setStatus("Reloaded panel code and restarted polling.");
        forceCheckNow(); // cancel + re-arm the polling task and run a check now
    } catch (e) {
        $.global.__mcpBridgeReloading = false;
        logToPanel("Reload error: " + e.toString());
    }
}

if (!__mcpReloading) {
var buttonRow = panel.add("group", undefined);
buttonRow.orientation = "row";

// Reload: pulls the latest handler code off disk, fully resets the poller
// (cancels + re-arms the scheduled task, clears isChecking), and runs an
// immediate synchronous check - combines the old "Reload Panel" and
// "Force Check Now" buttons into one action.
var reloadButton = buttonRow.add("button", undefined, "Reload");
reloadButton.onClick = function() { reloadBridge(); };

// Log startup
logToPanel("MCP Bridge started");
logToPanel("Command file: " + getCommandFilePath());
statusText.text = "Ready - Auto-run is " + (autoRunCheckbox.value ? "ON" : "OFF");

// Start the command checker
startCommandChecker();

// Self-heal watchdog: onActivate fires whenever the panel gains focus (docking/
// undocking, clicking into it, AE bringing it forward), which — like a button
// click — always reaches AE's event loop even when app.scheduleTask has
// stalled. If polling looks dead (no check ran for 3+ intervals), re-arm it
// automatically instead of waiting for someone to notice and click "Force
// Check Now". This piggybacks on ordinary panel focus during normal AE use —
// no dedicated user action required.
panel.onActivate = function () {
    var idleFor = new Date().getTime() - lastPollAt;
    if (idleFor > checkInterval * 3) {
        logToPanel("Self-heal: poll loop looked stalled (idle " + Math.round(idleFor / 1000) + "s), re-arming.");
        isChecking = false;
        startCommandChecker();
    }
};

// Lay out, and keep contents resizing with the panel/window frame.
panel.layout.layout(true);
panel.layout.resize();
panel.onResizing = panel.onResize = function () { this.layout.resize(); };

// Only a floating Window needs to be centered and shown; a docked Panel is already visible.
if (panel instanceof Window) {
    panel.center();
    panel.show();
}
}
